import { useEffect, useState } from 'react';
import api from '../api/client';

export default function TicketList({ refreshKey = 0 }) {
  // TICKETS
  const [tickets, setTickets] = useState([]);

  // FILTER STATES
  const [ticketIdSearch, setTicketIdSearch] = useState('');
  const [departmentFilter, setDepartmentFilter] = useState('');
  const [divisionSearch, setDivisionSearch] = useState('');
  const [moduleFilter, setModuleFilter] = useState('');
  const [submoduleFilter, setSubmoduleFilter] = useState('');
  const [status, setStatus] = useState('');

  // DROPDOWN DATA
  const [departments, setDepartments] = useState([]);
  const [modules, setModules] = useState([]);
  const [submodules, setSubmodules] = useState([]);

  // PAGINATION
  const [page, setPage] = useState(1);
  const [count, setCount] = useState(0);
  const [nextPage, setNextPage] = useState(null);
  const [previousPage, setPreviousPage] = useState(null);

  // LOAD DROPDOWNS
  const loadDropdowns = async () => {
    try {
      const [deptRes, moduleRes, submoduleRes] = await Promise.all([
        api.get('/departments/'),
        api.get('/modules/'),
        api.get('/submodules/'),
      ]);

      setDepartments(deptRes.data || []);
      setModules(moduleRes.data || []);
      setSubmodules(submoduleRes.data || []);
    } catch (err) {
      console.error('Failed to load dropdowns', err);
    }
  };

  // LOAD TICKETS
  const loadTickets = async (pageNo = page) => {
    try {
      const params = {
        page: pageNo,
      };

      // FILTERS
      if (ticketIdSearch) {
        params.ticket_id = ticketIdSearch;
      }

      if (departmentFilter) {
        params.department = departmentFilter;
      }

      if (divisionSearch) {
        params.division = divisionSearch;
      }

      if (moduleFilter) {
        params.module = moduleFilter;
      }

      if (submoduleFilter) {
        params.submodule = submoduleFilter;
      }

      if (status) {
        params.status = status;
      }

      const res = await api.get('/tickets/', { params });

      const data = res.data;

      setTickets(data.results || []);
      setCount(data.count || 0);
      setNextPage(data.next);
      setPreviousPage(data.previous);
    } catch (err) {
      console.error('Failed to load tickets', err);
    }
  };

  // INITIAL LOAD
  useEffect(() => {
    loadDropdowns();
  }, []);

  // PAGE CHANGE
  useEffect(() => {
    loadTickets(page);
  }, [refreshKey, page]);

  // APPLY FILTER
  const handleApply = () => {
    setPage(1);
    loadTickets(1);
  };

  // EXPORT EXCEL
  const handleExport = async () => {
    try {
      const params = {};

      if (ticketIdSearch) {
        params.ticket_id = ticketIdSearch;
      }

      if (departmentFilter) {
        params.department = departmentFilter;
      }

      if (divisionSearch) {
        params.division = divisionSearch;
      }

      if (moduleFilter) {
        params.module = moduleFilter;
      }

      if (submoduleFilter) {
        params.submodule = submoduleFilter;
      }

      if (status) {
        params.status = status;
      }

      const res = await api.get('/tickets/export_excel/', {
        params,
        responseType: 'blob',
      });

      const url = window.URL.createObjectURL(new Blob([res.data]));

      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', 'tickets.xlsx');

      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) {
      console.error('Export failed', err);
    }
  };

  // TOTAL PAGES
  const totalPages = Math.ceil(count / 8);

  return (
    <div>

      {/* FILTER SECTION */}
      <div className="row mb-3 g-2">

        {/* TICKET ID */}
        <div className="col-md-2">
          <input
            type="text"
            className="form-control"
            placeholder="Ticket ID"
            value={ticketIdSearch}
            onChange={(e) => setTicketIdSearch(e.target.value)}
          />
        </div>

        {/* DEPARTMENT */}
        <div className="col-md-2">
          <select
            className="form-select"
            value={departmentFilter}
            onChange={(e) => setDepartmentFilter(e.target.value)}
          >
            <option value="">All Departments</option>

            {departments.map((dept) => (
              <option key={dept.id} value={dept.id}>
                {dept.name}
              </option>
            ))}
          </select>
        </div>

        {/* DIVISION */}
        <div className="col-md-2">
          <input
            type="text"
            className="form-control"
            placeholder="Division"
            value={divisionSearch}
            onChange={(e) => setDivisionSearch(e.target.value)}
          />
        </div>

        {/* MODULE */}
        <div className="col-md-2">
          <select
            className="form-select"
            value={moduleFilter}
            onChange={(e) => setModuleFilter(e.target.value)}
          >
            <option value="">All Modules</option>

            {modules.map((module) => (
              <option key={module.id} value={module.id}>
                {module.name}
              </option>
            ))}
          </select>
        </div>

        {/* SUBMODULE */}
        <div className="col-md-2">
          <select
            className="form-select"
            value={submoduleFilter}
            onChange={(e) => setSubmoduleFilter(e.target.value)}
          >
            <option value="">All Submodules</option>

            {submodules.map((submodule) => (
              <option key={submodule.id} value={submodule.id}>
                {submodule.name}
              </option>
            ))}
          </select>
        </div>

        {/* STATUS */}
        <div className="col-md-2">
          <select
            className="form-select"
            value={status}
            onChange={(e) => setStatus(e.target.value)}
          >
            <option value="">All Status</option>
            <option value="Open">Open</option>
            <option value="In Progress">In Progress</option>
            <option value="Resolved by Support">
              Resolved by Support
            </option>
            <option value="Sent to Developer">
              Sent to Developer
            </option>
            <option value="Developer In Progress">
              Developer In Progress
            </option>
            <option value="Closed">Closed</option>
            <option value="Reopened">Reopened</option>
          </select>
        </div>

        {/* APPLY BUTTON */}
        <div className="col-md-2 d-grid">
          <button
            className="btn btn-primary"
            onClick={handleApply}
          >
            Apply
          </button>
        </div>

        {/* EXPORT BUTTON */}
        <div className="col-md-2 d-grid">
          <button
            className="btn btn-success"
            onClick={handleExport}
          >
            Export Excel
          </button>
        </div>
      </div>

      {/* TABLE */}
      <div className="table-responsive">
        <table className="table table-bordered table-striped">
          <thead>
            <tr>
              <th>Ticket ID</th>
              <th>Department</th>
              <th>Division</th>
              <th>Module</th>
              <th>Submodule</th>
              <th>Subject</th>
              <th>Status</th>
              <th>Decision</th>
              <th>Created</th>
              <th>Closed Date</th>
            </tr>
          </thead>

          <tbody>
            {tickets.length > 0 ? (
              tickets.map((ticket) => (
                <tr key={ticket.id}>

                  <td>{ticket.ticket_id}</td>

                  <td>{ticket.department_name || ''}</td>

                  <td>{ticket.division_name || ''}</td>

                  <td>{ticket.module_name || ''}</td>

                  <td>{ticket.submodule_name || ''}</td>

                  <td>{ticket.subject}</td>

                  <td>{ticket.status}</td>

                  <td>{ticket.support_decision}</td>

                  <td>
                    {ticket.created_at
                      ? new Date(ticket.created_at).toLocaleString()
                      : ''}
                  </td>

                  <td>
                    {ticket.closed_at
                      ? new Date(ticket.closed_at).toLocaleString()
                      : ''}
                  </td>

                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="10" className="text-center">
                  No tickets found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* PAGINATION */}
      <div className="d-flex justify-content-between align-items-center mt-3">

        <div>
          Total Tickets: <strong>{count}</strong>
        </div>

        <div className="d-flex align-items-center gap-2">

          <button
            className="btn btn-outline-secondary"
            disabled={!previousPage}
            onClick={() => setPage((prev) => prev - 1)}
          >
            Previous
          </button>

          <span>
            Page <strong>{page}</strong> of{' '}
            <strong>{totalPages || 1}</strong>
          </span>

          <button
            className="btn btn-outline-secondary"
            disabled={!nextPage}
            onClick={() => setPage((prev) => prev + 1)}
          >
            Next
          </button>

        </div>
      </div>
    </div>
  );
}
